const body = $input.first().json.body || $input.first().json;
const data = body.data || body;
if (data?.key?.fromMe) return [];
const from = (data?.key?.remoteJid || '').replace('@s.whatsapp.net','').replace(/\D/g,'');
if (!from) return [];
const keys = data?.message ? Object.keys(data.message) : [];
const msgType = keys.find(k => !['senderKeyDistributionMessage','messageContextInfo'].includes(k)) || '';
const msgText = (data?.message?.conversation || data?.message?.extendedTextMessage?.text || data?.message?.imageMessage?.caption || '').trim();
const hasImage = ['imageMessage','documentMessage','documentWithCaptionMessage'].includes(msgType);
const codes = msgText.toUpperCase().split(/[\n,;]+/).map(l=>l.trim().replace(/\s+/g,'')).filter(l=>/^[A-Z]{2,3}\d{1,2}$|^FWC\d{1,2}$|^00$/.test(l));
const isOrderKw = /\b(PEDIR|PEDIDO|COMPRAR|QUERO)\b/.test(msgText.toUpperCase());
const isReceiptKw = /comprovante|paguei|pago|transferi|enviei|pixado|realizei/i.test(msgText);
const isReceipt = hasImage || isReceiptKw;
let routeType = 'ignore';
if (codes.length > 0 && isOrderKw) routeType = 'order';
else if (isReceipt) routeType = 'receipt';
else if (codes.length > 0) routeType = 'stock';
return [{ json: { from, msgText, codes, hasImage, routeType } }];

const stockData = Array.isArray($input.first().json) ? $input.first().json : [];
const parseData = $('Parse e Rota').first().json;
const { from, codes } = parseData;
function preco(c) {
  if (!c) return 1;
  if (c === '00' || c.startsWith('FWC')) return 2;
  if (/^[A-Z]{2,3}1$/.test(c)) return 2;
  return 1;
}
function precoDesc(c, n) {
  const b = preco(c), sp = b === 2;
  if (n >= 500) return sp ? 1.85 : 0.85;
  if (n >= 250) return sp ? 1.90 : 0.90;
  if (n >= 150) return sp ? 1.95 : 0.95;
  return b;
}
function brl(v) { return 'R$ ' + v.toFixed(2).replace('.', ','); }
const map = new Map(stockData.map(s => [s.code, s]));
const disp = [], indisp = [];
for (const c of codes) {
  const s = map.get(c);
  if (s && s.quantity > 0) disp.push({ sticker_id: s.id, code: c, name: s.name });
  else indisp.push(c);
}
if (disp.length === 0) {
  return [{ json: { from, routeType: 'no_stock', msg: '😕 Nenhuma das figurinhas solicitadas está disponível no momento.\n\nTente novamente ou entre em contato!' } }];
}
const totalQty = disp.length;
const totalValor = disp.reduce((a, s) => a + precoDesc(s.code, totalQty), 0);
let descMsg = '';
if (totalQty >= 500) descMsg = '\n🏷️ _Desconto de 15% aplicado!_';
else if (totalQty >= 250) descMsg = '\n🏷️ _Desconto de 10% aplicado!_';
else if (totalQty >= 150) descMsg = '\n🏷️ _Desconto de 5% aplicado!_';
const linhasDisp = disp.map(s => `  ✅ ${s.code} — ${brl(precoDesc(s.code, totalQty))}`);
const linhasIndisp = indisp.map(c => `  ❌ ${c}`);
const pixKey = '15991460543';
const msg = [
  '🏷️ *Figurinhas Copa 2026 — Pedido Confirmado!*', '',
  `*Disponíveis (${disp.length}):*`,
  ...linhasDisp,
  ...(indisp.length > 0 ? ['', `*Indisponíveis (${indisp.length}):*`, ...linhasIndisp] : []),
  '', `💰 *Total: ${brl(totalValor)}*${descMsg}`, '',
  '━━━━━━━━━━━━━━━━━',
  '💳 *Pagamento via PIX*', '',
  `🔑 *Chave PIX (Telefone):*\n\`${pixKey}\``,
  '', `📌 *Como pagar:*\n1. Abra seu banco\n2. PIX → Pagar\n3. Digite a chave acima\n4. Confirme: *${brl(totalValor)}*\n5. 📸 Envie o comprovante aqui`,
  '━━━━━━━━━━━━━━━━━', '',
  '_Após o comprovante separamos suas figurinhas!_ 📦'
].join('\n');
const items = disp.map(s => ({ sticker_id: s.sticker_id, sticker_code: s.code, sticker_name: s.name, quantity: 1, unit_price: precoDesc(s.code, totalQty) }));
return [{ json: { from, msg, totalValor, items, routeType: 'order' } }];

const orders = Array.isArray($input.first().json) ? $input.first().json : [];
const from = $('Parse e Rota').first().json.from;
const order = orders[0] || null;
const msgCliente = order
  ? [
      '✅ *Comprovante recebido!*', '',
      `Seu pedido *#${order.id.slice(0,8).toUpperCase()}* foi confirmado.`,
      '📦 Estamos separando suas figurinhas!',
      '', '_Em breve entraremos em contato para combinar a entrega._ 😊'
    ].join('\n')
  : '✅ *Comprovante recebido!*\n\nEm breve confirmaremos seu pedido. 📦';
const totalStr = order ? `R$ ${Number(order.total_value).toFixed(2).replace('.',',')}` : '—';
const buyerName = order?.buyer_name || from;
const orderId = order ? `#${order.id.slice(0,8).toUpperCase()}` : 'novo';
const msgVendedor = [
  '🔔 *Comprovante de pagamento recebido!*', '',
  `👤 *Cliente:* ${buyerName}`,
  `📱 *WhatsApp:* ${from}`,
  `💰 *Valor:* ${totalStr}`,
  `📋 *Pedido:* ${orderId}`, '',
  '👉 Acesse o painel e *confirme o pagamento* para dar baixa no estoque.'
].join('\n');
return [{ json: { from, msgCliente, msgVendedor } }];

const stockData = Array.isArray($input.first().json) ? $input.first().json : [];
const parseData = $('Parse e Rota').first().json;
const { from, codes } = parseData;
function preco(c) {
  if (!c) return 1;
  if (c === '00' || c.startsWith('FWC')) return 2;
  if (/^[A-Z]{2,3}1$/.test(c)) return 2;
  return 1;
}
function precoDesc(c, n) {
  const b = preco(c), sp = b === 2;
  if (n >= 500) return sp ? 1.85 : 0.85;
  if (n >= 250) return sp ? 1.90 : 0.90;
  if (n >= 150) return sp ? 1.95 : 0.95;
  return b;
}
function brl(v) { return 'R$ ' + v.toFixed(2).replace('.', ','); }
const map = new Map(stockData.map(s => [s.code, s]));
const disp = [], indisp = [];
for (const c of codes) {
  const s = map.get(c);
  if (s && s.quantity > 0) disp.push({ code: c, qty: s.quantity });
  else indisp.push(c);
}
const totalQty = disp.length;
let descMsg = '';
if (totalQty >= 500) descMsg = '\n🏷️ _15% de desconto aplicado!_';
else if (totalQty >= 250) descMsg = '\n🏷️ _10% de desconto aplicado!_';
else if (totalQty >= 150) descMsg = '\n🏷️ _5% de desconto aplicado!_';
else if (totalQty >= 100) descMsg = '\n💡 _Com 150+ figurinhas você ganha 5% de desconto!_';
let msg = '🔍 *Verificação de estoque*\n\n';
if (disp.length > 0) {
  const total = disp.reduce((a, s) => a + precoDesc(s.code, totalQty), 0);
  msg += `*Disponíveis (${disp.length}):*\n`;
  msg += disp.map(s => `  ✅ ${s.code} — ${brl(precoDesc(s.code, totalQty))}`).join('\n') + '\n';
  msg += `\n💰 *Total: ${brl(total)}*${descMsg}\n`;
}
if (indisp.length > 0) {
  msg += `\n*Indisponíveis (${indisp.length}):*\n`;
  msg += indisp.map(c => `  ❌ ${c}`).join('\n') + '\n';
}
if (disp.length > 0) {
  msg += '\n_Para comprar, envie a lista com a palavra *PEDIR*_ 🛒';
}
return [{ json: { from, msg } }];
